### RED フェーズ

`.claude/skills/dev/spec-run/scripts/__tests__/sync-spec-md.test.mjs` に symlink 経由 subprocess テストを追加する:

```js
import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import { spawnSync } from 'node:child_process';
import { mkdtempSync, symlinkSync, writeFileSync, rmSync, mkdirSync, readFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join, resolve } from 'node:path';

describe('isDirectRun (symlink 経由)', () => {
  let tmpDir;
  let symlinkedScript;
  const originalScript = resolve('.claude/skills/dev/spec-run/scripts/sync-spec-md.mjs');

  beforeAll(() => {
    tmpDir = mkdtempSync(join(tmpdir(), 'sync-spec-md-symlink-'));
    symlinkedScript = join(tmpDir, 'sync-spec-md.mjs');
    symlinkSync(originalScript, symlinkedScript);

    // 最小のダミー spec ディレクトリを作成
    const specDir = join(tmpDir, 'spec');
    mkdirSync(specDir);
    const tasksJson = { schemaVersion: 2, gates: [], todos: [] };
    writeFileSync(join(specDir, 'tasks.json'), JSON.stringify(tasksJson));
    writeFileSync(join(specDir, 'spec.md'), '<!-- generated:begin -->\nold\n<!-- generated:end -->\n');
  });

  afterAll(() => {
    rmSync(tmpDir, { recursive: true, force: true });
  });

  it('symlink 経由で起動しても main() が実行されて spec.md が更新される', () => {
    const tasksPath = join(tmpDir, 'spec', 'tasks.json');
    const result = spawnSync('node', [symlinkedScript, tasksPath], { encoding: 'utf-8' });
    expect(result.status).toBe(0);
    const specContent = readFileSync(join(tmpDir, 'spec', 'spec.md'), 'utf-8');
    expect(specContent).not.toContain('old');
    expect(specContent).toContain('<!-- generated:begin -->');
  });
});
```

→ `npm test` で RED（新規テストが落ちる）を確認

### GREEN フェーズ

`.claude/skills/dev/spec-run/scripts/sync-spec-md.mjs` の冒頭 import に以下を追加:

```js
import { readFileSync, writeFileSync, existsSync, realpathSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { pathToFileURL } from 'node:url';
```

末尾（line 148-155 付近）の isDirectRun ブロックを以下に置き換え:

```js
// 直接実行時のみ main を呼ぶ（symlink 経由でも動作するよう realpath 解決）
const isDirectRun = import.meta.main ?? (
  process.argv[1] &&
  import.meta.url === pathToFileURL(realpathSync(process.argv[1])).href
);
if (isDirectRun) {
  main();
}
```

→ `npm test` で全通過（既存 + 新規）を確認

